final:
module SR_latch(
    input wire S,
    input wire R,
    input wire clk,
    output reg obf_Q,
    output reg Q_bar
);
    always @(posedge clk) begin
        if (S && ~R) begin
            obf_Q <= 1'b1;
            Q_bar <= 1'b0;
        end else if (~S && R) begin
            obf_Q <= 1'b0;
            Q_bar <= 1'b1;
        end 
    end
endmodule
